import React from 'react';
import { Link } from 'react-router-dom';

const Header = () => {
  return (
    <header className="bg-yellow-500 text-white py-4 shadow-md">
      <div className="container mx-auto px-4">
        <div className="flex flex-col md:flex-row items-center justify-between">
          <Link to="/" className="flex items-center space-x-3 mb-4 md:mb-0">
            <i className="fas fa-shield-alt text-3xl"></i>
            <div>
              <h1 className="text-xl font-bold">Assurance Décennale Électricien</h1>
              <p className="text-sm text-yellow-100">Devis en ligne gratuit</p>
            </div>
          </Link>
          <div className="flex items-center space-x-4">
            <div className="text-right">
              <p className="text-sm text-yellow-100">Conseil personnalisé</p>
              <a href="tel:0182834800" className="text-xl font-bold hover:text-yellow-200">01 82 83 48 00</a>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
